    for (var i=0; i<sender.eeChildren.length; i++) {
        if (sender.eeChildren[i].style.visibility != "hidden") {
            if (sender.eeChildren[i].close) {
                sender.eeChildren[i].close();
                ee.setVisible(this, false);
            } else {
                ee.showAni(sender.eeChildren[i], 1);
            }
        }
    }
}

